def process_dynamic_feed(raw_records):
    clean_items = []
    for item in raw_records:
        if item is None:
            continue
        if isinstance(item, str):
            cleaned = item.strip().title()
            if cleaned:
                clean_items.append(cleaned)
        elif isinstance(item, float):
            clean_items.append(round(item, 2))
        elif isinstance(item, int):
            clean_items.append(item)
        elif isinstance(item, list):
            clean_items.append([x for x in item if x is not None])

    return {
        'processed_count': len(clean_items),
        'items': clean_items
    }

feed = ['  alice  ', 42, 99.998, None, [1, 2], '  BOB  ']
result = process_dynamic_feed(feed)
print(result)
